<script>		var torochan = <?php if(isset($aftereffect)) echo $aftereffect; else echo '0'; ?>;		if (torochan > 0) window.open("<?php echo base_url("hotline"); ?>/print_faktur/"+torochan);		function validateForm() {			var check = true;			var error = '<div class="alert alert-danger alert-dismissable"><button type="button" class="close" data-dismiss="alert" aria-hidden="true">&times;</button><i class="fa fa-info-circle"></i>  <strong>ERROR!</strong><br />';			// check apakah tanggal sudah terisi			if ($("#tanggal").val()=='') {				check = false;				error += 'Anda harus mengisi tanggal Purchase Order<br/>';			}			// check apakah customer terisi			if ($("#customer").val()=='') {				check = false;				error += 'Anda harus mengisi customer yang melakukan pemesanan<br/>';			}			// check input spare part			var rowCount = $('#toro tr').length;			if (rowCount < 2) {				check = false;				error += 'Anda harus mengisi spare part apa saja yang dipesan, minimal 1 part';			}			error += '</div>';			if (check == false) $("#error-area").html(error);			return check;		}				function motor_selected() {			if ($('#customer-motor').val() == '') $('#motor-area').html('');			else {				$.get("<?php echo base_url("hotline"); ?>/auto_motor_selected?q="+$('#customer-motor').val(), function(data) {					$("#motor-area").html(data);				});			}		}				function deleted(id) {			var rowCount = $('#toro tr').length;			$('#t-'+id).remove();			var i = id;			for (i=id+1;i<rowCount;i++) {				$('#t-'+i).attr("id","t-"+(i-1));				$('#t0-'+i).html(i-1);				$('#t0-'+i).attr("id","t0-"+(i-1));				$('#t1-'+i).attr("id","t1-"+(i-1));				$('#t2-'+i).attr("id","t2-"+(i-1));				$('#t3-'+i).attr("id","t3-"+(i-1));				$('#t4-'+i).attr("id","t4-"+(i-1));				$('#t5-'+i).attr("id","t5-"+(i-1));				$('#t6-'+i).html('<a class="btn btn-small" href="#" onclick="deleted('+(i-1)+');">Remove</a>');				$('#t6-'+i).attr("id","t6-"+(i-1));				$('input[name="ids['+(i-1)+']"]').attr("name","ids["+(i-2)+"]");				$('input[name="banyak['+(i-1)+']"]').attr("name","banyak["+(i-2)+"]");				$('input[name="po_id['+(i-1)+']"]').attr("name","po_id["+(i-2)+"]");				$('input[name="po_nama['+(i-1)+']"]').attr("name","po_nama["+(i-2)+"]");			}			hitung();		}				function hitung() {			var rowCount = $('#toro tr').length;			var rowCount1 = $('#toroserv tr').length;			var toro = 0; var toro1 = 0;			var sub = 0; var sub1 = 0;			var diskon = 0; var diskon1 = 0;			var total = 0; var total1 = 0;			for (var i=2;i<=rowCount;i++) {				toro = toro + parseInt($('input[name="banyak['+(i-2)+']"]').val());			}			$('#total-jenis').html(rowCount-1);			$('#total-part').html(toro);		}				<?php if (isset($detils)) echo 'hitung();'; ?>				$(function() {			function log(id,label) {				var rowCount = $('#toro tr').length;				//check apakah sudah ada atau belum				var temu = 0;				for (var i = 2; i <= rowCount; i++) {					var j = $('input[name="ids['+(i-2)+']"]').val();					var k = parseInt($('input[name="banyak['+(i-2)+']"]').val());					if (j == id) {						$('input[name="banyak['+(i-2)+']"]').val(k+1);						temu = 1;					}				}				if (temu == 0) {					$('#toro-body').append('<tr id="t-'+rowCount+'"><td id="t0-'+rowCount+'">'+rowCount+						'</td><td id="t1-'+rowCount+'">'+id+						'</td><td id="t2-'+rowCount+'">'+label+'<input type="hidden" name="ids['+(rowCount-1)+']" value="'+id+						'"></td><td id="t3-'+rowCount+'"><input class="form-control" type="text" name="po_id['+(rowCount-1)+						'"></td><td id="t4-'+rowCount+'"><input class="form-control" type="text" name="po_nama['+(rowCount-1)+						'"></td><td id="t5-'+rowCount+'"><input class="form-control" type="number" name="banyak['+(rowCount-1)+						']" value="1"></td><td id="t6-'+rowCount+						'"><a class="btn btn-danger" href="#" onclick="deleted('+rowCount+');"><i class="fa fa-trash"></i> Remove</a></td></tr>');				}				$("input[type='number']").change(function(){					hitung();				});				hitung();				} 			$("#city").autocomplete({				source: function( request, response ) {					$.ajax({						url: "<?php echo base_url("po"); ?>/auto_barang",						dataType: "json",						data: {							q: request.term						},						success: function( data ) {							response( data );						}					});				},				minLength: 1,				select: function( event, ui ) {					log(ui.item.value, ui.item.label1);					$("#city").val( '' );					return false;				},				focus: function( event, ui ) {					$("#city").val( ui.item.label );					return false;				},				open: function() {					$( this ).removeClass( "ui-corner-all" ).addClass( "ui-corner-top" );				},				close: function() {					$( this ).removeClass( "ui-corner-top" ).addClass( "ui-corner-all" );				}			});						$("#customer-name").autocomplete({				source: function( request, response ) {					$.ajax({						url: "<?php echo base_url("po"); ?>/auto_customer",						dataType: "json",						data: {							q: request.term						},						success: function( data ) {							response( data );						}					});				},				minLength: 1,				select: function( event, ui ) {					$('input[name="customer"]').val(ui.item.value);					var custdetil = '<address><strong>'+ui.item.label+'</strong><br>'+ui.item.alamat+						'<br><abbr title="Phone">P:</abbr> '+ui.item.telp+'</address>';					$("#customer-area").html(custdetil);					return false;				},				focus: function( event, ui ) {					$("#customer-name").val( ui.item.label );					return false;				},			});						$("#tanggal").datepicker({				dateFormat : "yy-mm-dd",				showButtonPanel : true			});		});	</script>